#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1010;const double INF=2e15;
struct Sort
{
	int x,y;inline Sort(const int xx=0,const int yy=0){x=xx;y=yy;}
	inline bool operator<(const Sort &xx)const{return x<xx.x;}
}Q[N];

double dp[N][N];
inline double Cnt(int x,int y){return sqrt(1.0*(Q[x].x-Q[y].x)*(Q[x].x-Q[y].x)+(Q[x].y-Q[y].y)*(Q[x].y-Q[y].y));}
inline void Solve(int n)
{
//	print(INF);
	rep(1,n,i){int x=read(),y=read();Q[i]=Sort(x,y);}
	rep(0,n,i)rep(0,n,j)dp[i][j]=INF;sort(Q+1,Q+n+1);
	dp[2][1]=Cnt(2,1);
	rep(3,n,i)
	{
		rep(1,i-2,j)dp[i][i-1]=min(dp[i][i-1],dp[i-1][j]+Cnt(i,j));
		rep(1,i-2,j)dp[i][j]=min(dp[i][j],dp[i-1][j]+Cnt(i-1,i));
	}
	double ans=INF;rep(1,n-1,i)ans=min(ans,dp[n][i]+Cnt(i,n));
	printf("%.2lf\n",ans);
}
signed main(){int n;while(cin>>n)Solve(n);return 0;}
